      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        DEFINITION: sREPRESENTED_DEFINITION, 
        USED_REPRESENTATION: eREPRESENTATION.PRef
      ) {

        self._definition = DEFINITION
        self._used_representation = USED_REPRESENTATION

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( DEFINITION: original._definition, USED_REPRESENTATION: original._used_representation )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: sREPRESENTED_DEFINITION.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]DEFINITION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: eREPRESENTATION.PRef.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]USED_REPRESENTATION for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( DEFINITION: p0, USED_REPRESENTATION: p1 )
      }
    }
